  ('retired-7ec62a85-moex-00193', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '「不收費的高速公路」為具備下列何種特性的廣義公共財？ 獨占性  交易性  擁擠性  分割性', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00194', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '學者摩根（G. Morgen）將組織比喻成八種不同的意象，下列敘述何者錯誤？ 組織作為機器的意象，意味著組織是一個精心設計的有機體 組織作為大腦的意象，意指組織可以扮演整合分析之功能 組織作為流變與轉型的意象，代表著組織不斷進行變遷 組織作為宰制工具的意象，說明了組織對於內部員工的壓迫', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00195', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '「政府推動公共政策能夠反映一般社會大眾或政策利害關係人的偏好」，這是公共行政何種價值 的體現？ 公平性  回應性  經濟性  開放性', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00196', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '依據中央行政機關組織基準法之規定，下列何者正確？ 立法院各級機關組織名稱依此法律設置 機關組織以法律定之者，其組織法律定名為法或通則 機關內部單位區分為業務單位及總務單位 獨立機關為依法獨立行使職權之首長制機關', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00197', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '關於「組織為適應環境變遷，透過策略運用，藉提供成員個人心性發展與交流的機會，建構有效 的人際關係，以達成個人與組織目標的實現」之論述，最接近下列何種概念？ 組織發展  組織病象  組織設計  組織倫理', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00198', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '稀缺性高科技人才的人事制度設計之核心原則，下列何者較不適用？ 企業家精神  市場競爭  層級節制  創意績效', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00199', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '有關我國現行公務人員俸給制度的內涵，下列敘述何者正確？ 本俸是底薪，年功俸是績效薪 服務處所越偏遠，職務加給越高 經銓敘審定之俸級應予保障，非依法律不得降級或減俸 各機關得依機關特性，另行自定俸給項目及數額支給', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00200', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '有關「國民租稅負擔率」的敘述，下列何者正確？ 可作為衡量社會福利支出是否有效率的指標 即政府賦稅收入占國內生產毛額的比率 我國近5年的國民租稅負擔率介於45~55%之間 提高租稅負擔率的方式之一為降低公共支出', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00201', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '若我國中央政府總預算案未及於會計年度開始前完成三讀，對政府單位預算的運作有何影響？ 政府單位除必要工作者（essential workers）可繼續上班之外，其他人員應暫停上班，直到預算 案完成三讀為止 由總統頒布臨時預算，作為各機關預算執行之依據 如總預算案未能如期完成三讀，依法視同自動完成三讀，故對政府運作其實並無任何影響 新興資本支出及新增計畫須待預算審議完成後始得動支', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00202', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-3a7b2121', 'sub-retired-7ec62a85-03', NULL, 'single_choice', '政府採購法分為公開招標、選擇性招標及限制性招標三種招標程序，關於此三種招標程序之規定， 下列敘述何者正確？ 三種招標方式都需經公告程序  公開招標與選擇性招標需經公告程序 公開招標與限制性招標需經公告程序  僅公開招標需經公告程序 13550、13750', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "c2599dae9b73", "answer_pdf_sha1": "f7374d0ecbee", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL)
